#include <stdio.h>
#include <string.h>
int main() {
    char s[101];
    scanf("%s", s);
    int count = 0;
    for (int i = 0; i < strlen(s); i++) {
        int flag = 0;
        for (int j = 0; j < i; j++) {
            if (s[i] == s[j]) {
                flag = 1;
                break;
            }
        }
        if (flag == 0) count++;
    }
    if (count % 2 == 0) printf("GIRL\n");
    else printf("BOY\n");
    return 0;
}

code.C++:
#include <iostream>
#include <string>
using namespace std;
int main() {
    string s;
    cin >> s;
    int count = 0;
    for (int i = 0; i < s.length(); i++) {
        bool flag = false;
        for (int j = 0; j < i; j++) {
            if (s[i] == s[j]) {
                flag = true;
                break;
            }
        }
        if (!flag) count++;
    }
    if (count % 2 == 0) cout << "GIRL" << endl;
    else cout << "BOY" << endl;
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String s = scanner.next();
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            boolean flag = false;
            for (int j = 0; j < i; j++) {
                if (s.charAt(i) == s.charAt(j)) {
                    flag = true;
                    break;
                }
            }
            if (!flag) count++;
        }
        if (count % 2 == 0) System.out.println("GIRL");
        else System.out.println("BOY");
    }
}

