code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.on('line', (s) => {
    let count = 0;
    let uniqueChars = new Set();
    for (let i = 0; i < s.length; i++) {
        if (!uniqueChars.has(s[i])) {
            uniqueChars.add(s[i]);
            count++;
        }
    }
    if (count % 2 == 0) console.log('GIRL');
    else console.log('BOY');
});

